func TestSplitForThreadRespectsCharLimitWithNumberingSuffix(t *testing.T) {
	// Three paragraphs of ~200 chars each force a multi-tweet thread; every
	// rendered tweet (body + " (i/n)" suffix) must stay within the limit.
	para := strings.Repeat("word ", 40) // 200 chars
	md := strings.Join([]string{para, para, para}, "\n\n")
	parts, err := SplitForThread(md, tweetCharLimit)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(parts) < 2 {
		t.Fatalf("expected a multi-tweet thread, got %d parts", len(parts))
	}
	n := len(parts)
	for i, p := range parts {
		rendered := numberedTweet(p, i, n)
		if got := utf8.RuneCountInString(rendered); got > tweetCharLimit {
			t.Fatalf("tweet %d/%d is %d chars, over limit %d: %q", i+1, n, got, tweetCharLimit, rendered)
		}
	}
}

func TestSplitForThreadNeverSplitsInsideCodeFence(t *testing.T) {
	md := "Intro paragraph.\n\n```go\nfunc main() {}\n```\n\nOutro paragraph."
	parts, err := SplitForThread(md, tweetCharLimit)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	// The fenced block is a single atom: exactly one part must contain the
	// complete fence (both delimiters), and no part may carry a stray half.
	var fenceParts int
	for _, p := range parts {
		open := strings.Contains(p, "```go")
		close := strings.Contains(p, "```\n") || strings.HasSuffix(strings.TrimSpace(p), "```")
		if open || strings.Contains(p, "func main") {
			fenceParts++
			if !open || !close {
				t.Fatalf("code fence was split across tweets: %q", p)
			}
		}
	}
	if fenceParts != 1 {
		t.Fatalf("expected the fenced block in exactly one tweet, found in %d", fenceParts)
	}
}

